mapper.update:
update scheduled_tasks set name=#{name}, cron_expression=#{cronExpression}, enabled=#{enabled},
lock_ttl_seconds=#{lockTtlSeconds}, next_fire_at=#{nextFireAt}, registration_status=#{registrationStatus},
trace_id=#{traceId}, created_at=#{createdAt}, updated_at=#{updatedAt} where task_key=#{taskKey}

mapper.select:
select  from scheduled_tasks
where enabled=true and registration_status='REGISTERED' and next_fire_at is not null and next_fire_at <= #{now}
order by next_fire_at, task_key limit #{limit}

mapper.update:
update scheduled_task_plans set task_key=#{taskKey}, owner_user_id=#{ownerUserId},
cron_expression=#{cronExpression}, payload_json=#{payloadJson}, enabled=#{enabled},
next_fire_at=#{nextFireAt}, trace_id=#{traceId}, created_at=#{createdAt}, updated_at=#{updatedAt}
where plan_id=#{planId}

mapper.select:
select  from scheduled_task_runs
where trigger_type=#{triggerType} and status='PENDING' and scheduled_fire_at <= #{now}

    and execution_affinity=#{executionAffinity}
    and execution_affinity is null

order by scheduled_fire_at, id limit #{limit}
